/**
 * Mirrors AI SDK `UIMessage["role"]`.
 *
 * React rx-ai source: packages/rx-ai/src/lib/message/message.tsx
 */
export type MessageRole = 'user' | 'assistant' | 'system';

/**
 * Subset of the AI SDK `FileUIPart` shape used by MessageAttachment.
 * Kept local so consumers do not have to install the `ai` package just
 * to render an attachment.
 */
export interface MessageAttachmentData {
  filename?: string;
  mediaType?: string;
  url?: string;
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';
import { cn } from '@gremorie/ng-core';

import type { MessageRole } from './message.types';

/**
 * Message — root container for a chat bubble.
 *
 * Mirrors React `Message` from rx-ai. The `from` input drives the
 * `is-user` / `is-assistant` group classes that descendants
 * (`MessageContent`) read with `group-[.is-user]:*` Tailwind variants.
 *
 * @example
 * ```html
 * <message from="user">
 *   <message-content>Hello!</message-content>
 * </message>
 * ```
 */
@Component({
  selector: 'message',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ng-content />`,
  host: {
    '[class]': 'hostClass()',
  },
})
export class Message {
  readonly from = input.required<MessageRole>();

  protected readonly hostClass = computed(() =>
    cn(
      'group flex w-full max-w-[95%] flex-col gap-2',
      this.from() === 'user'
        ? 'is-user ml-auto justify-end'
        : 'is-assistant',
    ),
  );
}

import {
  ChangeDetectionStrategy,
  Component,
  ViewEncapsulation,
} from '@angular/core';

/**
 * MessageContent — bubble body. Styled differently for user vs assistant via
 * the `is-user` / `is-assistant` group class set by the parent `<message>`.
 */
@Component({
  selector: 'message-content',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ng-content />`,
  host: {
    class:
      'is-user:dark flex w-fit max-w-full min-w-0 flex-col gap-2 overflow-hidden text-sm group-[.is-user]:ml-auto group-[.is-user]:rounded-lg group-[.is-user]:bg-secondary group-[.is-user]:px-4 group-[.is-user]:py-3 group-[.is-user]:text-foreground group-[.is-assistant]:text-foreground',
  },
})
export class MessageContent {}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';
import { cn } from '@gremorie/ng-core';

/**
 * MessageAvatar — circular avatar.
 *
 * Mirrors React `MessageAvatar`. Renders `<img>` when `src` is set, otherwise
 * falls back to projected content (initials, icon, etc.).
 */
@Component({
  selector: 'message-avatar',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    @if (src()) {
      <img
        [src]="src()"
        [alt]="alt() ?? name() ?? 'avatar'"
        class="size-full object-cover"
      />
    } @else {
      <ng-content />
    }
  `,
  host: {
    '[class]': 'hostClass()',
  },
})
export class MessageAvatar {
  readonly src = input<string>();
  readonly alt = input<string>();
  readonly name = input<string>();

  protected readonly hostClass = computed(() =>
    cn(
      'inline-flex size-8 shrink-0 items-center justify-center overflow-hidden rounded-full bg-muted text-muted-foreground text-xs font-medium ring-1 ring-border',
    ),
  );
}

import {
  ChangeDetectionStrategy,
  Component,
  ViewEncapsulation,
} from '@angular/core';

/**
 * MessageActions — row of icon buttons (copy, retry, thumbs, etc.).
 */
@Component({
  selector: 'message-actions',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ng-content />`,
  host: {
    class: 'flex items-center gap-1',
  },
