@Component({
  selector: 'message-toolbar',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ng-content />`,
  host: {
    class: 'mt-4 flex w-full items-center justify-between gap-4',
