import {
  ChangeDetectionStrategy,
  Component,
  ViewEncapsulation,
} from '@angular/core';

/**
 * MessageAttachments — wrap-flex container for `<message-attachment>` items
 * inside a message bubble.
 */
@Component({
  selector: 'message-attachments',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ng-content />`,
  host: {
    class: 'ml-auto flex w-fit flex-wrap items-start gap-2',
  },
})
export class MessageAttachments {}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  output,
  ViewEncapsulation,
} from '@angular/core';

import type { MessageAttachmentData } from './message.types';

/**
 * MessageAttachment — image preview or file chip. Mirrors React
 * `MessageAttachment`. Emits `(removed)` when the optional remove button is
 * clicked; consumers opt in by setting `[removable]="true"`.
 */
@Component({
  selector: 'message-attachment',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    @if (isImage()) {
      <img
        [src]="data().url"
        [alt]="label()"
        class="size-full object-cover"
        height="100"
        width="100"
      />
    } @else {
      <div
        class="flex size-full shrink-0 items-center justify-center rounded-lg bg-muted text-muted-foreground"
        [attr.aria-label]="label()"
      >
        <!-- paperclip glyph (no icon-set dep) -->
        <svg
          width="16"
          height="16"
          viewBox="0 0 24 24"
          fill="none"
          stroke="currentColor"
          stroke-width="2"
          stroke-linecap="round"
          stroke-linejoin="round"
          aria-hidden="true"
        >
          <path d="m21 11-8.99 9a5.5 5.5 0 0 1-7.78-7.78l8.49-8.49a3.5 3.5 0 1 1 4.95 4.95L8.93 17.07a1.5 1.5 0 0 1-2.12-2.12l8.49-8.49" />
        </svg>
      </div>
    }
    @if (removable()) {
      <button
        type="button"
        (click)="handleRemove($event)"
        class="absolute top-2 right-2 inline-flex size-6 items-center justify-center rounded-full bg-background/80 p-0 opacity-0 backdrop-blur-sm transition-opacity hover:bg-background group-hover:opacity-100"
        aria-label="Remove attachment"
      >
        <svg
          width="12"
          height="12"
          viewBox="0 0 24 24"
          fill="none"
          stroke="currentColor"
          stroke-width="2"
          stroke-linecap="round"
          stroke-linejoin="round"
          aria-hidden="true"
        >
          <path d="M18 6 6 18M6 6l12 12" />
        </svg>
        <span class="sr-only">Remove</span>
      </button>
    }
  `,
  host: {
    class: 'group relative size-24 overflow-hidden rounded-lg',
  },
})
export class MessageAttachment {
  readonly data = input.required<MessageAttachmentData>();
  readonly removable = input<boolean>(false);

  readonly removed = output<void>();

  protected readonly isImage = computed(() => {
    const d = this.data();
    return !!d.mediaType?.startsWith('image/') && !!d.url;
  });

  protected readonly label = computed(() => {
    const d = this.data();
    return d.filename || (this.isImage() ? 'Image' : 'Attachment');
  });

  protected handleRemove(event: MouseEvent): void {
    event.stopPropagation();
    this.removed.emit();
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  input,
  ViewEncapsulation,
} from '@angular/core';
import { DomSanitizer, type SafeHtml } from '@angular/platform-browser';
import { marked, type MarkedOptions } from 'marked';

/**
 * MessageResponse — assistant-side response body with markdown rendering.
 *
 * Mirrors React `MessageResponse` (which wraps `Streamdown` from rx-ai).
 * Streaming-aware: accepts partial markdown each render and re-parses;
 * marked is robust to incomplete input (open code fences, half tables)
 * and degrades gracefully back to plain text on parse failure.
 *
 * Consumers can also project arbitrary children (custom renderer) instead
 * of using the `text` input.
 *
 * `marked` is a hard runtime dep of ng-ai (kept tiny and tree-shakable).
 */
@Component({
  selector: 'message-response',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    @if (text(); as t) {
      <div [innerHTML]="renderedHtml()"></div>
    } @else {
      <ng-content />
    }
  `,
  host: {
    class:
      'size-full prose prose-sm dark:prose-invert max-w-none [&>*:first-child]:mt-0 [&>*:last-child]:mb-0',
  },
})
export class MessageResponse {
  private readonly sanitizer = inject(DomSanitizer);

  /**
   * Markdown source. Re-parsed on every change; streaming-friendly. Leave
   * unset and project markdown / HTML children when using a custom
   * renderer.
   */
  readonly text = input<string>();

  /**
   * Optional marked options forwarded to the parser. Defaults to
   * `{ gfm: true, breaks: false }` matching Streamdown defaults.
   */
  readonly markedOptions = input<MarkedOptions | undefined>(undefined);

  protected readonly renderedHtml = computed<SafeHtml>(() => {
    const source = this.text() ?? '';
    if (!source) return '';

    const options: MarkedOptions = {
      gfm: true,
      breaks: false,
      ...(this.markedOptions() ?? {}),
    };

    try {
      const html = marked.parse(source, { ...options, async: false }) as string;
      return this.sanitizer.bypassSecurityTrustHtml(html);
    } catch (err) {
      console.warn('[ng-ai] MessageResponse markdown parse failed', err);
      return this.sanitizer.bypassSecurityTrustHtml(escapeHtml(source));
    }
  });
}

function escapeHtml(s: string): string {
  return s
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

import {
  AfterContentInit,
  ChangeDetectionStrategy,
  Component,
  computed,
  Directive,
  effect,
  forwardRef,
  inject,
  InjectionToken,
  input,
  OnDestroy,
  output,
  signal,
  TemplateRef,
  ViewEncapsulation,
} from '@angular/core';

/**
 * Shared state contract for the MessageBranch family. Mirrors the React
 * `MessageBranchContext`. Distributed via DI under `MESSAGE_BRANCH`.
 */
export interface MessageBranchState {
  readonly currentBranch: () => number;
  readonly totalBranches: () => number;
  goToPrevious: () => void;
  goToNext: () => void;
  registerBranch: (template: TemplateRef<unknown>) => () => void;
  branches: () => readonly TemplateRef<unknown>[];
}

export const MESSAGE_BRANCH = new InjectionToken<MessageBranchState>(
  'MessageBranchState',
);

/**
 * Wraps a single branch template. Equivalent to one child of React's
 * `<MessageBranchContent>` array.
 */
@Directive({
  selector: '[messageBranchItem]',
  standalone: true,
})
export class MessageBranchItem implements AfterContentInit, OnDestroy {
  readonly template = inject(TemplateRef);
  private readonly parent = inject(MESSAGE_BRANCH);
  private unregister?: () => void;

  ngAfterContentInit(): void {
    this.unregister = this.parent.registerBranch(this.template);
  }

  ngOnDestroy(): void {
    this.unregister?.();
  }
}

/**
 * MessageBranch — controllable branch picker. Mirrors React `MessageBranch`.
 *
 * Self-provides `MESSAGE_BRANCH` so children inject the same instance via
 * Angular's component-hierarchy DI - no shared mutable singleton, fully
 * compatible with multiple concurrent branches on the page.
 */
@Component({
  selector: 'message-branch',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ng-content />`,
  host: {
    class: 'grid w-full gap-2 [&>div]:pb-0',
  },
  providers: [
    {
      provide: MESSAGE_BRANCH,
      useExisting: forwardRef(() => MessageBranch),
    },
  ],
})
export class MessageBranch implements MessageBranchState {
  readonly defaultBranch = input<number>(0);
  readonly branchChange = output<number>();

  private readonly _branches = signal<readonly TemplateRef<unknown>[]>([]);
  private readonly _current = signal(0);

  readonly branches = () => this._branches();
  readonly currentBranch = () => this._current();
  readonly totalBranches = computed(() => this._branches().length);

  constructor() {
    // Apply defaultBranch when it changes.
    effect(() => {
      this._current.set(this.defaultBranch());
    });
  }

  registerBranch(template: TemplateRef<unknown>): () => void {
    this._branches.update((prev) => [...prev, template]);
    return () => {
      this._branches.update((prev) => prev.filter((t) => t !== template));
    };
  }

  goToPrevious(): void {
    const total = this.totalBranches();
    if (total <= 1) return;
    const cur = this._current();
    const next = cur > 0 ? cur - 1 : total - 1;
    this._current.set(next);
    this.branchChange.emit(next);
  }

  goToNext(): void {
    const total = this.totalBranches();
    if (total <= 1) return;
    const cur = this._current();
    const next = cur < total - 1 ? cur + 1 : 0;
    this._current.set(next);
    this.branchChange.emit(next);
  }
}

import { NgTemplateOutlet } from '@angular/common';
import {
  ChangeDetectionStrategy,
  Component,
  computed,
  contentChildren,
  inject,
  ViewEncapsulation,
} from '@angular/core';

import { MESSAGE_BRANCH } from './message-branch';
import { MessageBranchItem } from './message-branch';

/**
 * MessageBranchContent — renders only the currently active branch template.
 *
 * Children are wrapped with `[messageBranchItem]` directives so the parent
 * MessageBranch can index them. Mirrors React `MessageBranchContent`.
 */
@Component({
  selector: 'message-branch-content',
  standalone: true,
  imports: [NgTemplateOutlet],
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    @for (item of items(); track $index) {
      <div
        class="grid gap-2 overflow-hidden [&>div]:pb-0"
        [class.hidden]="$index !== current()"
      >
        <ng-container *ngTemplateOutlet="item.template" />
      </div>
    }
  `,
})
export class MessageBranchContent {
  protected readonly state = inject(MESSAGE_BRANCH);
  protected readonly items = contentChildren(MessageBranchItem, {
    descendants: true,
  });
  protected readonly current = computed(() => this.state.currentBranch());
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { MESSAGE_BRANCH } from './message-branch';
import type { MessageRole } from './message.types';

/**
 * MessageBranchSelector — wrapper for the prev/next/page controls. Hides
 * itself when there is only one branch. Mirrors React `MessageBranchSelector`.
 */
@Component({
  selector: 'message-branch-selector',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    @if (visible()) {
      <div
        class="inline-flex items-center [&>*:not(:first-child)]:rounded-l-md [&>*:not(:last-child)]:rounded-r-md"
      >
        <ng-content />
      </div>
    }
  `,
})
export class MessageBranchSelector {
  readonly from = input.required<MessageRole>();

  private readonly state = inject(MESSAGE_BRANCH);
  protected readonly visible = computed(() => this.state.totalBranches() > 1);
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  ViewEncapsulation,
} from '@angular/core';

import { MESSAGE_BRANCH } from './message-branch';

/**
 * MessageBranchPrevious — "previous branch" icon button. Disabled when there
 * is only one branch. Mirrors React `MessageBranchPrevious`.
 */
@Component({
  selector: 'message-branch-previous',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <button
      type="button"
      class="inline-flex size-7 items-center justify-center rounded-md text-muted-foreground transition-colors hover:bg-accent hover:text-accent-foreground disabled:opacity-50"
      aria-label="Previous branch"
      [disabled]="disabled()"
      (click)="prev()"
    >
      <svg
        width="14"
        height="14"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        stroke-width="2"
        stroke-linecap="round"
        stroke-linejoin="round"
        aria-hidden="true"
      >
        <path d="m15 18-6-6 6-6" />
      </svg>
    </button>
  `,
})
export class MessageBranchPrevious {
  private readonly state = inject(MESSAGE_BRANCH);
  protected readonly disabled = computed(() => this.state.totalBranches() <= 1);

  protected prev(): void {
    this.state.goToPrevious();
  }
}

/**
 * MessageBranchNext — "next branch" icon button. Disabled when there is only
 * one branch. Mirrors React `MessageBranchNext`.
 */
@Component({
  selector: 'message-branch-next',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <button
      type="button"
      class="inline-flex size-7 items-center justify-center rounded-md text-muted-foreground transition-colors hover:bg-accent hover:text-accent-foreground disabled:opacity-50"
      aria-label="Next branch"
      [disabled]="disabled()"
      (click)="next()"
    >
      <svg
        width="14"
        height="14"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        stroke-width="2"
        stroke-linecap="round"
        stroke-linejoin="round"
        aria-hidden="true"
      >
        <path d="m9 18 6-6-6-6" />
      </svg>
    </button>
  `,
})
export class MessageBranchNext {
  private readonly state = inject(MESSAGE_BRANCH);
  protected readonly disabled = computed(() => this.state.totalBranches() <= 1);

  protected next(): void {
    this.state.goToNext();
  }
}

/**
 * MessageBranchPage — "X of Y" pagination label. Mirrors React
 * `MessageBranchPage`.
 */
@Component({
  selector: 'message-branch-page',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<span>{{ label() }}</span>`,
  host: {
    class:
      'inline-flex items-center px-2 text-muted-foreground text-xs font-medium',
  },
})
export class MessageBranchPage {
  private readonly state = inject(MESSAGE_BRANCH);
  protected readonly label = computed(
    () => `${this.state.currentBranch() + 1} of ${this.state.totalBranches()}`,
  );
}

export * from './message.types';
export { Message } from './message';
export { MessageContent } from './message-content';
export { MessageAvatar } from './message-avatar';
export { MessageActions } from './message-actions';
export { MessageAction } from './message-action';
export { MessageToolbar } from './message-toolbar';
export { MessageAttachments } from './message-attachments';
export { MessageAttachment } from './message-attachment';
export { MessageResponse } from './message-response';
export {
  MessageBranch,
  MessageBranchItem,
  MESSAGE_BRANCH,
} from './message-branch';
export type { MessageBranchState } from './message-branch';
export { MessageBranchContent } from './message-branch-content';
export { MessageBranchSelector } from './message-branch-selector';
export {
  MessageBranchPrevious,
  MessageBranchNext,
  MessageBranchPage,
} from './message-branch-controls';
